#include <iostream>
#include <vector>
using namespace std;
class Node {
 public:
  int val;
  Node* next;
  Node(int val) : val(val), next(nullptr) {}
};
class Solution {
 public:
  Node* merge(Node* head1, Node* head2) {
    if (!head1) return head2;
    Node* merged = head1;
    Node* curr = head1;
    while (head2) {
      Node* next = head2->next;
      if (curr->val < head2->val) {
        curr->next = head2;
        curr = curr->next;
      } else {
        curr->next = merged;
        curr = curr->next->next;
      }
      head2 = next;
    }
    return merged;
  }
};
int main() {
  Solution solution;
  Node* head1 = new Node(1);
  head1->next = new Node(3);
  head1->next->next = new Node(9);
  head1->next->next->next = new Node(5);
  head1->next->next->next->next = new Node(2);
  head1->next->next->next->next->next = new Node(4);
  head1->next->next->next->next->next->next = new Node(7);
  head1->next->next->next->next->next->next->next = new Node(6);

  Node* head2 = new Node(3);
  head2->next = new Node(6);
  head2->next->next = new Node(8);
  head2->next->next->next = new Node(5);
  head2->next->next->next->next = new Node(1);
  head2->next->next->next->next->next = new Node(0);
  head2->next->next->next->next->next->next = new Node(8);
  head2->next->next->next->next->next->next->next = new Node(4);

  Node* merged = solution.merge(head1, head2);
  while (merged) {
    cout << merged->val << ' ';
    merged = merged->next;
  }
  return 0;
}
